example.code:
# Enable versioning for backup bucket
gcloud storage buckets update gs://my-backups --versioning

# View versions of an object
gcloud storage objects describe gs://my-backups/backup-2026-04-29.tar.gz --all-versions

# Retrieve specific version
gcloud storage cp gs://my-backups/backup-2026-04-29.tar.gz#VERSION_ID ./backup-restore.tar.gz

# Configure noncurrent version cleanup via lifecycle (see lifecycle-rules section)
# Keep only 3 noncurrent versions, delete older
{
  "rule": [
    {
      "action": {"type": "Delete"},
      "condition": {"numNewerVersions": 3, "isLive": false}
    }
  ]
}
